#include <stdio.h>
#include <stdlib.h>

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N1,N2; scanf("%d %d", &N1, &N2);
        long long *S1 = (long long*)malloc(N1*sizeof(long long));
        long long *S2 = (long long*)malloc(N2*sizeof(long long));
        for(int i=0;i<N1;i++) scanf("%lld", &S1[i]);
        for(int i=0;i<N2;i++) scanf("%lld", &S2[i]);
        int i=0,j=0; long long diff=0; int turn=0; // 0 Alice, 1 Bob
        while(i<N1 || j<N2){
            long long v1 = (i<N1)? S1[i] : -1LL; // -1 works because values are >=1
            long long v2 = (j<N2)? S2[j] : -1LL;
            if(v1>=v2){
                if(turn==0) diff+=v1; else diff-=v1;
                i++;
            }else{
                if(turn==0) diff+=v2; else diff-=v2;
                j++;
            }
            turn ^= 1;
        }
        printf("%lld\n", diff);
        free(S1); free(S2);
    }
    return 0;
}

