import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        StringBuilder sb = new StringBuilder();
        while (T-- > 0) {
            int N1 = fs.nextInt();
            int N2 = fs.nextInt();
            long[] s1 = new long[N1];
            long[] s2 = new long[N2];
            for (int i = 0; i < N1; i++) s1[i] = fs.nextLong();
            for (int i = 0; i < N2; i++) s2[i] = fs.nextLong();
            int i = 0, j = 0;
            long diff = 0;
            boolean alice = true;
            while (i < N1 || j < N2) {
                long v1 = (i < N1) ? s1[i] : -1L;
                long v2 = (j < N2) ? s2[j] : -1L;
                if (v1 >= v2) {
                    diff += alice ? v1 : -v1;
                    i++;
                } else {
                    diff += alice ? v2 : -v2;
                    j++;
                }
                alice = !alice;
            }
            sb.append(diff).append('\n');
        }
        System.out.print(sb.toString());
    }

    // Fast scanner for large input
    static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in) { this.in = in; }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        long nextLong() throws IOException {
            int c; do { c = readByte(); } while (c <= ' ');
            boolean neg = false;
            if (c == '-') { neg = true; c = readByte(); }
            long val = 0;
            while (c > ' ') {
                val = val * 10 + (c - '0');
                c = readByte();
            }
            return neg ? -val : val;
        }
        int nextInt() throws IOException { return (int) nextLong(); }
    }
}

